"""
MKT Original Language Commentary — John chapters 12–13
Run: python3 scripts/zc-original-john-12-13.py

Source data used:
- data/interlinear/john.json
- data/translation/glossary-greek.json (contested terms)
- data/translation/notes/john.json (translation reasoning)
- data/translation/draft/mediating/john.json (MKT text for quoting)

Key decisions in this range:
- 12:3 ναρδου πιστικῆς: "pure nard" follows the sense of "genuine/unadulterated" for πιστικῆς (root from πίστις,
  possibly "reliable-quality"); the meaning is debated but "expensive" is captured by πολυτίμου separately
- 12:7 εἰς τὴν ἡμέραν τοῦ ἐνταφιασμοῦ ἀφῇ αὐτό: the syntax is difficult — best read as proleptic: she
  kept it for (i.e., in view of) this day of burial; ἐνταφιασμός occurs only here and Matt 26:12 in NT
- 12:32 πάντας (disp=1): universal reach is the best reading; "all kinds of people" is the theological
  implication but the Greek says πάντας, not πάντα or πᾶς τις
- 12:38 λόγος (disp=3): here means "oracle/report/word spoken" (Isa 53:1 context), not the Logos of John 1:1
- 13:1 εἰς τέλος: temporal ("to the end") and qualitative ("completely/fully") senses both defensible and
  likely intentional; MKT renders "to the end" preserving the temporal thrust
- 13:10 λελουμένος / νίψασθαι: the λούω/νίπτω distinction (full bath vs. partial wash) is exegetically
  significant; some MSS omit "except his feet" (εἰ μὴ τοὺς πόδας) — the shorter reading may be secondary
- 13:35 ἀγάπη (disp=3): the contested range runs from "warm affection" to "selfless, covenant-forming love";
  the Johannine context (καθὼς ἠγάπησα ὑμᾶς) indicates the latter
- Evangelist is used consistently for the narrator/author throughout (following prior John original scripts)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


JOHN = {
  "12": {
    "1": '<p><strong>ἓξ ἡμέραι πρὸ τοῦ πάσχα</strong> — "six days before the Passover." The Evangelist\'s precise temporal marker ties Jesus\' arrival at Bethany to the Passover calendar. Under Levitical practice the Passover lamb was selected on Nisan 10 — exactly six days before Nisan 14, the day of slaughter. The timing is unlikely to be accidental.</p><p><strong>ὃν ἤγειρεν ἐκ νεκρῶν</strong> — "whom he raised from the dead," aorist of <em>egeirō</em> (G1453). The clause is explanatory — the Evangelist re-anchors Lazarus as the embodied evidence that draws the crowd (v.9), making Bethany the staging point for the final confrontation.</p>',
    "2": '<p><strong>ἐδιακόνει</strong> — imperfect of <em>diakoneō</em> (G1247): "was serving." The imperfect marks the service as ongoing throughout the meal, not a single act. Martha\'s characteristic activity (Luke 10:40 uses the same verb) appears here without contrast or rebuke — the dinner context is hospitable, not polemical.</p><p><strong>ἀνακειμένων</strong> — present participle of <em>anakeimai</em> (G345), "reclining at table." Formal Passover preparation and Greco-Roman banquet practice both called for reclining, distinguishing festive meals from ordinary eating. Lazarus reclining alongside Jesus underlines the physical reality of the resurrection.</p>',
    "3": '<p><strong>λίτραν μύρου νάρδου πιστικῆς</strong> — <em>litra</em> (G3046) is the Roman pound (~327g, a large quantity). <em>Nardos</em> (spikenard, from the Himalayan plant <em>Nardostachys jatamansi</em>) was imported from India and priced accordingly. <em>Pistikēs</em> (G4101, related to <em>pistis</em>) most probably means "genuine" or "unadulterated" — a quality marker, not a place-name. The construction means "a pound of genuine, costly spikenard."</p><p><strong>ἤλειψεν τοὺς πόδας</strong> — "anointed the feet," <em>aleiphō</em> (G218), the more common term for anointing with oil or perfume (as opposed to the sacred-appointment sense of <em>chriō</em>). Anointing feet rather than the head is unusual and underlines the extravagance and humility simultaneously.</p><p><strong>ἐπλήρωθη ἡ οἰκία</strong> — "the house was filled" (<em>plēroō</em>, G4137, aorist passive). The filling of the house with fragrance is the Evangelist\'s detail that no other account shares — functioning as a sensory witness to the scene\'s excess.</p>',
    "4": '<p><strong>ὁ μέλλων αὐτὸν παραδιδόναι</strong> — "the one about to betray him," present participle of <em>mellō</em> + infinitive of <em>paradidōmi</em> (G3860). The participle is progressive: the betrayal plan is already underway, not a future contingency. The Evangelist introduces Judas here, before his objection, to prime the reader to hear the "concern for the poor" as performance rather than conviction.</p>',
    "5": '<p><strong>τριακοσίων δηναρίων</strong> — "three hundred denarii." A denarius was the standard daily wage for a laborer (Matt 20:2), making 300 denarii roughly a full year\'s earnings. Judas\'s calculation correctly identifies the extravagance, which is the point — the anointing is deliberately disproportionate.</p>',
    "6": '<p><strong>κλέπτης ἦν</strong> — "he was a thief," <em>kleptēs</em> (G2812), imperfect of <em>eimi</em>. The imperfect marks this as an established characteristic, not a new development. The Evangelist\'s retrospective comment here is the only place in the Gospels where Judas is called a thief outright.</p><p><strong>τὸ γλωσσόκομον εἶχεν</strong> — "he had the money bag." <em>Glōssokomon</em> (G1101) originally referred to a case for mouthpieces of reed instruments, then repurposed for any small box or bag. The imperfect <em>eichen</em> again marks it as a continuing arrangement — Judas managed the group\'s finances habitually.</p><p><strong>ἐβάσταζεν</strong> — "was stealing/carrying," <em>bastazō</em> (G941). The verb means both "to carry" (his legitimate role) and in Hellenistic usage "to pilfer" — the Evangelist deploys the ambiguity deliberately. Both senses are likely intended: he carried the bag and carried off its contents.</p>',
    "7": '<p><strong>ἄφες αὐτήν</strong> — "leave her alone," aorist imperative of <em>aphiēmi</em> (G863), abrupt and final. The command overrides Judas entirely and defends Mary without explanation of her motives.</p><p><strong>εἰς τὴν ἡμέραν τοῦ ἐνταφιασμοῦ τετήρηκεν αὐτό</strong> — "she has kept it for the day of my burial." <em>Entaphiasmos</em> (G1780, preparation for burial) occurs in NT only here and Matt 26:12. <em>Tetērēken</em> is perfect active of <em>tēreō</em> (G5083) — "she has kept/reserved it." Whether Mary consciously acted for the burial or Jesus reinterprets her act proleptically is intentionally ambiguous; the syntax allows both readings. What the Evangelist underlines is that the anointing is oriented toward death, not celebration.</p>',
    "8": '<p><strong>τοὺς πτωχοὺς πάντοτε ἔχετε μεθ\' ἑαυτῶν</strong> — "the poor you always have with you," echoing Deut 15:11 ("for there will never cease to be poor in the land"). The allusion does not demean the poor or charitable care for them; it situates the present moment as exceptional — this particular act, at this particular moment, is unrepeatable.</p><p><strong>ἐμὲ δὲ οὐ πάντοτε ἔχετε</strong> — "but me you do not always have." The contrast is temporal: the anointing is possible only now, before the death Jesus is moving toward.</p>',
    "9": '<p><strong>ἔγνω ὄχλος πολύς</strong> — "a large crowd learned" (aorist of <em>ginōskō</em>, G1097). The crowd\'s motivation is split: not only Jesus but Lazarus — the Evangelist signals that the resurrection of Lazarus has become an independent attraction, complicating the authorities\' attempts to manage public response.</p>',
    "10": '<p><strong>ἵνα καὶ τὸν Λάζαρον ἀποκτείνωσιν</strong> — "in order that they might kill Lazarus also," purpose clause with aorist subjunctive of <em>apokteinō</em> (G615). The logic of silencing a living sign by killing it is grimly ironic — killing the one Jesus raised would only re-demonstrate the claim. The chief priests\' decision is self-defeating, but fear overrides reason.</p>',
    "11": '<p><strong>ὅτι πολλοὶ δι᾽ αὐτὸν ὑπῆγον</strong> — "because many on account of him were going away," imperfect of <em>hypagō</em> (G5217). The imperfect marks a gradual, ongoing defection from the Jerusalem leadership\'s sphere of influence. <em>Hyp</em>agō can mean simply "to go" but in Johannine usage often implies movement from one sphere to another (cf. 8:21).</p><p><strong>ἐπίστευον εἰς τὸν Ἰησοῦν</strong> — "were believing in Jesus," imperfect again — the belief is spreading incrementally, not as a single event.</p>',
    "12": '<p><strong>τῇ ἐπαύριον</strong> — "the next day," marking the scene shift from the intimate dinner at Bethany to the public approach to Jerusalem. The movement from private to public is a Johannine structural feature across the passion week.</p><p><strong>ὁ ὄχλος πολύς ὁ ἐλθὼν εἰς τὴν ἑορτήν</strong> — "the large crowd that had come to the festival." The antecedent crowd is the Passover pilgrimage crowd, distinct from the Bethany observers. Both groups converge for the triumphal entry.</p>',
    "13": '<p><strong>βαΐα τῶν φοινίκων</strong> — "branches of palm trees," <em>baia</em> (G902) appears only here in NT. Palms were carried at the Feast of Tabernacles (Lev 23:40) and were a symbol of Jewish national and military victory (1 Macc 13:51; 2 Macc 10:7). Waving palms at Passover time, when Tabernacles palms were not customary, is a politically charged gesture.</p><p><strong>ὡσαννά</strong> — <em>hōsanna</em> (G5614), a transliteration of Hebrew הוֹשִׁיעָה נָּא, "save, pray!" (Ps 118:25). By the first century it had become a liturgical acclamation rather than a petition, roughly "hail!" or "praise God!" — though its original intercessory meaning likely lingered.</p><p><strong>εὐλογημένος ὁ ἐρχόμενος ἐν ὀνόματι κυρίου</strong> — Ps 118:26 LXX, the Hallel psalm sung at Passover. The crowd adds <strong>ὁ βασιλεὺς τοῦ Ἰσραήλ</strong> (king of Israel), an interpretive expansion not in the psalm text, making explicit the messianic reading.</p>',
    "14": '<p><strong>εὑρὼν δὲ ὁ Ἰησοῦς ὀνάριον</strong> — "having found a young donkey," aorist participle; <em>onarion</em> (G3678) is a diminutive — "little donkey" — found only here in NT. The act of finding and riding is understated; the Evangelist is pointing the reader to the prophetic text rather than the logistics.</p><p><strong>ἐκάθισεν ἐπ᾽ αὐτό</strong> — "sat on it," aorist of <em>kathizō</em> (G2523). The action fulfills the prophetic pattern; the brief narrative keeps attention on the significance, not the mechanics.</p>',
    "15": '<p><strong>Μὴ φοβοῦ, θύγατερ Σιών</strong> — "Do not fear, daughter Zion." The MT of Zech 9:9 reads "Rejoice greatly" (גִּילִי), but the LXX reads "rejoice" differently, and John\'s version "do not fear" may follow a variant LXX tradition or paraphrase. The address "daughter Zion" (a personification of Jerusalem) is retained.</p><p><strong>ἐπὶ πῶλον ὄνου</strong> — "on a donkey\'s colt," <em>pōlos</em> (G4454, colt), the same term as the LXX of Zech 9:9. John uses <em>onarion</em> in v.14 but quotes the LXX\'s <em>pōlos</em> in the fulfillment citation — a common citation practice: narrative freedom, lexical precision in the quotation.</p>',
    "16": '<p><strong>οὐκ ἔγνωσαν αὐτοῦ οἱ μαθηταί</strong> — "his disciples did not understand these things at first," aorist of <em>ginōskō</em>. The disciples\' incomprehension at significant moments is a recurring Johannine motif (cf. 2:22; 20:9).</p><p><strong>ὅτε ἐδοξάσθη Ἰησοῦς</strong> — "when Jesus was glorified," aorist passive of <em>doxazō</em> (G1392). In John "glorification" encompasses crucifixion, resurrection, and ascension as a single movement. The post-resurrection retrospect enables the disciples to connect the entry with Zechariah\'s text.</p><p><strong>γεγραμμένα</strong> — "written things," perfect passive participle of <em>graphō</em>: "the things standing written." The perfect tense is the Evangelist\'s standard way of marking scripture as permanently authoritative.</p>',
    "17": '<p><strong>ἐμαρτύρει οὖν ὁ ὄχλος</strong> — "the crowd was therefore testifying," imperfect of <em>martyreō</em> (G3140). The witnesses to the Lazarus event spread their testimony, generating the crowd of v.18. <em>Martyreō</em> is a forensic term — the crowd is functioning as legal witnesses to what they saw.</p>',
    "18": '<p><strong>διὰ τοῦτο καὶ ὑπήντησεν αὐτῷ ὁ ὄχλος</strong> — "for this reason the crowd met him," aorist of <em>hypantaō</em> (G5221). The Evangelist distinguishes the two crowds: those who went out because of what they heard Lazarus had been raised (v.18), and those who witnessed the event (v.17). Both groups testify, but their testimony has different epistemic weights.</p>',
    "19": '<p><strong>ὁ κόσμος ὀπίσω αὐτοῦ ἀπῆλθεν</strong> — "the whole world has gone after him," aorist of <em>aperchomai</em> (G565). The Pharisees\' frustrated hyperbole ("the whole world") is immediately followed by the arrival of Greeks (v.20), turning their exaggeration into unwitting prophecy. <em>Kosmos</em> in John\'s usage (cf. 3:16) carries precisely the universal scope the Pharisees dismiss as an idiom.</p>',
    "20": '<p><strong>Ἕλληνές τινες</strong> — "certain Greeks," most likely Gentile God-fearers or proselytes who came up to worship at the festival rather than diaspora Greek-speaking Jews. The arrival of Gentiles at this precise moment functions as the external trigger for Jesus\' declaration in v.23 that "the hour has come."</p>',
    "21": '<p><strong>Φιλίππῳ τῷ ἀπὸ Βηθσαϊδά</strong> — Philip from Bethsaida; both Philip and Andrew (v.22) bear Greek names, and Bethsaida was a border region with significant Gentile contact, making them natural intermediaries. The Evangelist\'s specificity here is not incidental — these disciples become the channel through which the Gentile approach reaches Jesus.</p><p><strong>ἠρώτων αὐτόν</strong> — "they were asking him," imperfect — repeated or persistent asking. <strong>ἰδεῖν τὸν Ἰησοῦν</strong> — "to see Jesus." <em>Theloō</em> + <em>horaō</em> infinitive; in Johannine idiom "to see" often carries the weight of genuine encounter with Jesus\' identity (cf. 1:39, 6:36).</p>',
    "22": '<p><strong>ἔρχεται Φίλιππος καὶ λέγει τῷ Ἀνδρέᾳ</strong> — historical presents (<em>erchomai</em>, <em>legō</em>) vivify the relay. Philip does not go directly to Jesus but consults Andrew first — possibly reflecting uncertainty about how Jesus would receive Gentiles, or a chain-of-command dynamic within the Twelve.</p>',
    "23": '<p><strong>ἐλήλυθεν ἡ ὥρα</strong> — "the hour has come," perfect of <em>erchomai</em> (G2064): "it has come and is now here." Throughout John 2–11, "the hour" of Jesus was either not yet come (2:4; 7:30; 8:20) or approaching (4:21, 23; 5:25, 28). The Gentiles\' request marks the transition: the universal mission Jesus is about to complete through death is now imminent.</p><p><strong>ἵνα δοξασθῇ ὁ Υἱὸς τοῦ ἀνθρώπου</strong> — purpose clause: "that the Son of Man might be glorified," aorist passive subjunctive of <em>doxazō</em>. The response to the Greeks\' desire to "see" Jesus is not an audience but an announcement of cross-death as the very means of glorification.</p>',
    "24": '<p><strong>ὁ κόκκος τοῦ σίτου</strong> — "the kernel of wheat," <em>kokkos sitou</em> (G2848, G4621). The grain-of-wheat image is Jesus\' own interpretation of his death — not merely loss but necessary precondition for fruitfulness. The logic is agricultural: buried seed is not wasted but productive.</p><p><strong>ἐὰν μὴ πέσῃ εἰς τὴν γῆν καὶ ἀποθάνῃ</strong> — "unless it falls into the earth and dies," two aorist subjunctives in a conditional. <em>Apothnēskō</em> (G599) is used for both literal death and the grain\'s ending — the metaphor turns on the word.</p><p><strong>μόνος μένει</strong> — "it remains alone," <em>monos</em> (G3441) + present of <em>menō</em> (G3306, to abide/remain). The contrast with <em>polun karpon pherei</em> (bears much fruit) is absolute: isolation vs. abundance, death vs. multiplication.</p>',
    "25": '<p><strong>ὁ φιλῶν τὴν ψυχὴν αὐτοῦ ἀπολλύει αὐτήν</strong> — "the one loving his life loses it." <em>Psychē</em> (G5590) appears in both clauses, creating the paradox that hinges on one word. <em>Phileō</em> (G5368, love with attachment) and <em>miseō</em> (G3404, hate) form the antithesis; but <em>miseo</em> here means "value less by comparison," a Semitic idiom of relative priority (cf. Luke 14:26).</p><p><strong>εἰς ζωὴν αἰώνιον φυλάξει αὐτήν</strong> — "will keep it for eternal life," future of <em>phylassō</em> (G5442). The keeping in view of <em>zōē aiōnios</em> (G2222 + G166) is the governing purpose — the apparent self-destruction is actually preservation at the highest level.</p>',
    "26": '<p><strong>ἐμοί τις διακονῇ, ἐμοὶ ἀκολουθείτω</strong> — "if anyone serves me, let him follow me," present subjunctive + present imperative. <em>Diakoneō</em> (G1247) and <em>akoloutheō</em> (G190) are paired: service to Jesus is inseparable from the pattern of following him — including through death.</p><p><strong>ὅπου εἰμὶ ἐγώ, ἐκεῖ καὶ ὁ διάκονος ὁ ἐμὸς ἔσται</strong> — "where I am, there also will my servant be." The ἐγώ is emphatic; the promise of co-location with Jesus is the reward of servant-following.</p><p><strong>τιμήσει αὐτόν</strong> — "will honor him," future of <em>timaō</em> (G5091). The Father\'s honoring of Christ\'s servant is the direct counterpart of the shame/dishonor that public discipleship brought in an honor-shame culture.</p>',
    "27": '<p><strong>ἡ ψυχή μου τετάρακται</strong> — "my soul has been troubled," perfect of <em>tarassō</em> (G5015). The perfect marks a present state resulting from a past disturbance — Jesus is not merely observing a coming trouble but is already in it. The same verb appears at 11:33 (the tomb of Lazarus) and 13:21 (announcing the betrayal) — <em>tarachthē</em> marks the moments of deepest human cost in the narrative.</p><p><strong>τί εἴπω; πάτερ, σῶσόν με ἐκ τῆς ὥρας ταύτης</strong> — the prayer-question is interrogative, not an actual petition: "What should I say? \'Father, save me from this hour\'?" The rhetorical structure immediately overturns the possibility: <strong>ἀλλὰ διὰ τοῦτο ἦλθον εἰς τὴν ὥρα ταύτην</strong> — "but for this very reason I came to this hour." This is the Johannine equivalent of the Synoptic Gethsemane — the struggle is present but the submission is immediate.</p>',
    "28": '<p><strong>δόξασόν σου τὸ ὄνομα</strong> — "glorify your name," aorist imperative of <em>doxazō</em>. The request is not for deliverance but for the Father\'s glorification — a reorientation from v.27\'s implicit plea.</p><p><strong>ἐδόξασα καὶ πάλιν δοξάσω</strong> — "I have glorified and will glorify again." The double aorist-future response from heaven (cf. John 12:30) encompasses past (the entire ministry) and future (the passion and exaltation). <em>Edoxasa</em> is aorist — a completed glorification; <em>doxasō</em> is future — the completing act is imminent.</p>',
    "29": '<p><strong>βροντὴν γεγονέναι… ἄγγελος αὐτῷ λελάληκεν</strong> — "that it had thundered… that an angel had spoken to him." The perfect infinitives (<em>gegonēnai</em> from <em>ginomai</em>, <em>lelalēken</em> from <em>laleō</em>) report completed events. The crowd\'s divided response — thunder vs. angel — illustrates the Johannine motif of differential hearing: the voice was audible but only partially intelligible.</p>',
    "30": '<p><strong>δι᾽ ὑμᾶς αὕτη ἡ φωνὴ γέγονεν, οὐ δι᾽ ἐμέ</strong> — "this voice has occurred for your sake, not for mine," perfect of <em>ginomai</em>. Jesus does not need the audible confirmation — it is for the witnesses. The statement implies that Jesus\' own confidence in the Father\'s glorification does not depend on public divine speech.</p>',
    "31": '<p><strong>νῦν κρίσις ἐστὶν τοῦ κόσμου τούτου</strong> — "now is the judgment of this world," <em>krisis</em> (G2920) in its judicial sense. The cross is the moment of cosmic adjudication — not the final judgment of all things but the definitive crisis in which the world\'s allegiance is exposed and the ruler\'s power broken.</p><p><strong>ὁ ἄρχων τοῦ κόσμου τούτου ἐκβληθήσεται ἔξω</strong> — "the ruler of this world will be cast out," future passive of <em>ekballō</em> (G1544). <em>Archōn</em> (G758, ruler) is used for the devil/Satan in John (14:30; 16:11) — a supernatural power over the world system, whose authority is broken at the cross, not merely threatened.</p>',
    "32": '<p><strong>κἀγὼ ἐὰν ὑψωθῶ ἐκ τῆς γῆς</strong> — "and I, if I am lifted up from the earth," aorist passive subjunctive of <em>hypsoō</em> (G5312). <em>Hypsoō</em> in John carries double freight: literal elevation on a cross (3:14; 8:28) and figurative exaltation to glory. The cross is simultaneously degradation and enthronement in Johannine theology.</p><p><strong>πάντας ἑλκύσω πρὸς ἐμαυτόν</strong> — "I will draw all people to myself," future of <em>helkyō</em> (G1670, to drag/draw). <em>Pantas</em> (all people, accusative plural) reaches beyond Israel — triggered precisely by the Greeks\' arrival (vv.20–21). The drawing is not automatic universalism but a statement of intended scope; cf. 6:44 where the Father draws those who will come.</p>',
    "33": '<p><strong>σημαίνων ποίῳ θανάτῳ ἤμελλεν ἀποθνῄσκειν</strong> — "signifying by what kind of death he was about to die," <em>sēmainō</em> (G4591, to indicate by sign or signal). The Evangelist\'s editorial comment connects "lifted up" (v.32) to crucifixion explicitly — completing the pattern established at 3:14 and 8:28.</p>',
    "34": '<p><strong>ἡμεῖς ἠκούσαμεν ἐκ τοῦ νόμου ὅτι ὁ Χριστὸς μένει εἰς τὸν αἰῶνα</strong> — "we have heard from the Law that the Christ remains forever." The crowd\'s appeal to "the Law" invokes texts like Ps 89:36–37 and Isa 9:7 (the eternal Davidic throne). They cannot reconcile "lifted up" with eternal messianic reign.</p><p><strong>τίς ἐστιν οὗτος ὁ Υἱὸς τοῦ ἀνθρώπου</strong> — "who is this Son of Man?" The question reveals that the crowd understands "Son of Man" as a messianic title but cannot integrate the death-trajectory with it. Their <em>nomos</em> hermeneutic is correct in its data but wrong in its interpretive frame.</p>',
    "35": '<p><strong>ἔτι μικρὸν χρόνον τὸ φῶς ἐν ὑμῖν ἐστιν</strong> — "still a little time the light is among you," <em>mikros</em> (G3398) + <em>chronos</em> (G5550). Jesus does not answer the crowd\'s question directly but shifts to urgent appeal. The temporal pressure ("a little while") is a characteristic Johannine device (7:33; 13:33; 16:16).</p><p><strong>περιπατεῖτε ὡς τὸ φῶς ἔχετε, ἵνα μὴ σκοτία ὑμᾶς καταλάβῃ</strong> — "walk while you have the light, so that darkness may not overtake you." <em>Katalambanō</em> (G2638, to seize/overtake) gives darkness an active, pursuing quality. The imperative <em>peripateite</em> (G4043, present — ongoing walking) frames discipleship as lived movement.</p>',
    "36": '<p><strong>πιστεύετε εἰς τὸ φῶς, ἵνα υἱοὶ φωτὸς γένησθε</strong> — "believe in the light, so that you may become sons of light," aorist subjunctive of <em>ginomai</em>. <em>Hyioi phōtos</em> (sons of light) is a Semitic idiom denoting people characterized by and belonging to the light — not just illuminated but constituted by it (cf. 1 Thess 5:5; Eph 5:8).</p><p><strong>ἀπελθὼν ἐκρύβη ἀπ᾽ αὐτῶν</strong> — "having gone away, he hid himself from them," aorist of <em>kryptō</em> (G2928). The withdrawal marks the close of Jesus\' public teaching; chapters 13–17 are private. The hiddenness also fulfills 12:35\'s warning about the light\'s departure.</p>',
    "37": '<p><strong>τοσαῦτα δὲ αὐτοῦ σημεῖα πεποιηκότος ἔμπροσθεν αὐτῶν οὐκ ἐπίστευον εἰς αὐτόν</strong> — "although he had done so many signs in their presence, they were not believing in him," imperfect of <em>pisteuō</em>. The perfect participle <em>pepoiēkotos</em> underlines the completed, abundant evidence; the imperfect <em>episteuon</em> marks the unbelief as an ongoing state in the face of it. Volume of evidence does not produce faith.</p>',
    "38": '<p><strong>ἵνα ὁ λόγος Ἠσαΐου τοῦ προφήτου πληρωθῇ</strong> — "that the word/oracle of Isaiah the prophet might be fulfilled." <em>Logos</em> (G3056, disp=3) here means "oracle" or "prophetic word" — not the metaphysical <em>Logos</em> of 1:1 but the spoken word of Isaiah. Isa 53:1 LXX is quoted essentially verbatim: <strong>κύριε, τίς ἐπίστευσεν τῇ ἀκοῇ ἡμῶν</strong> — "Lord, who believed our report?" <em>Akoē</em> (G189) means both "hearing" and "report/message heard" — the LXX renders the Hebrew שְׁמֻעָתֵנוּ accurately.</p>',
    "39": '<p><strong>διὰ τοῦτο οὐκ ἠδύναντο πιστεύειν</strong> — "for this reason they were not able to believe." <em>Dynamai</em> (G1410) + infinitive of <em>pisteuō</em> — a statement of incapacity, not merely unwillingness. The Evangelist is not eliminating human responsibility but is tracing the theological logic of Isaiah\'s text: the hardening is divinely permitted and scripturally anticipated.</p>',
    "40": '<p><strong>τετύφλωκεν αὐτῶν τοὺς ὀφθαλμούς</strong> — "he has blinded their eyes," perfect of <em>typhloō</em> (G5186). The divine subject of both verbs (blinds, hardens) in the Isa 6:10 citation is theologically difficult. Isa 6 depicts Isaiah\'s commissioning with a message that will produce judicial hardening — not that God wills unbelief as such but that the word of God exposes and confirms the orientation of the heart.</p><p><strong>ἐπώρωσεν αὐτῶν τὴν καρδίαν</strong> — "has hardened their hearts," perfect of <em>pōroō</em> (G4456), from <em>pōros</em> (hard stone, callus). The perfect tense in both verbs signals a state now established, not an ongoing process. John\'s version of the Isa 6:10 quotation differs from the LXX and from Matt 13:14-15 — it may follow a different textual tradition or be a paraphrase.</p>',
    "41": '<p><strong>ταῦτα εἶπεν Ἠσαΐας ὅτι εἶδεν τὴν δόξαν αὐτοῦ</strong> — "Isaiah said these things because he saw his glory," aorist of <em>horaō</em> (G3708). The pronoun <em>autou</em> (his) refers to Jesus — the Evangelist\'s astonishing exegetical claim is that the vision of Yahweh enthroned in Isa 6:1-3 was a vision of Christ\'s pre-incarnate glory. This is one of the highest Christological statements in the Gospel, made almost in passing.</p><p><strong>καὶ ἐλάλησεν περὶ αὐτοῦ</strong> — "and he spoke about him," aorist of <em>laleō</em>. The entire Isaiah 6 commission — including the hardening oracle — is understood as speech about Christ.</p>',
    "42": '<p><strong>ὅμως μέντοι καὶ ἐκ τῶν ἀρχόντων πολλοὶ ἐπίστευσαν εἰς αὐτόν</strong> — "nevertheless even many of the rulers believed in him." <em>Homōs mentoi</em> — a rare particle combination in NT (only here), meaning "nevertheless/nonetheless even so." The believing rulers are a significant qualification to the universal unbelief of vv.37–40.</p><p><strong>διὰ τοὺς Φαρισαίους οὐχ ὡμολόγουν</strong> — "because of the Pharisees they were not confessing," imperfect of <em>homologeō</em> (G3670, to confess/declare openly). The fear is institutional: the Pharisees have authority to exclude (cf. 9:22).</p>',
    "43": '<p><strong>ἠγάπησαν γὰρ τὴν δόξαν τῶν ἀνθρώπων μᾶλλον ἤπερ τὴν δόξαν τοῦ θεοῦ</strong> — "for they loved the glory of men more than the glory of God," aorist of <em>agapaō</em> (G25). The comparison <em>mallon ēper</em> (more than) reveals not absence of belief but divided loyalty. <em>Doxa</em> (G1391) appears twice — the same word, differently sourced: human approval vs. divine honor. In a shame/honor culture this is the ultimate diagnosis: miscalibrated honor attachment.</p>',
    "44": '<p><strong>Ἰησοῦς δὲ ἔκραξεν καὶ εἶπεν</strong> — "Jesus cried out and said," aorist of <em>krazō</em> (G2896, to cry out loud, often of urgent proclamation). The verb marks a public declaration rather than private teaching — a formal announcement after his withdrawal (v.36).</p><p><strong>ὁ πιστεύων εἰς ἐμὲ οὐ πιστεύει εἰς ἐμὲ ἀλλὰ εἰς τὸν πέμψαντά με</strong> — "the one believing in me does not believe in me only, but in the one who sent me." The construction is not paradoxical — it is relational: faith in Jesus is not isolated to his person but reaches through him to the Father. <em>Pempsanta</em> (aorist participle of <em>pempō</em>, G3992, to send) specifies the Father\'s active commissioning.</p>',
    "45": '<p><strong>ὁ θεωρῶν ἐμὲ θεωρεῖ τὸν πέμψαντά με</strong> — "the one seeing me sees the one who sent me," present participles. <em>Theōreō</em> (G2334) is the more intensive verb for seeing — to observe, behold, contemplate. The statement extends the faith-transparency of v.44 to vision: to look at Jesus is to look at the Father. Compare 14:9.</p>',
    "46": '<p><strong>ἐγὼ φῶς εἰς τὸν κόσμον ἐλήλυθα</strong> — "I have come as light into the world," perfect of <em>erchomai</em> — "I have come and remain present as light." The light/world declaration echoes the prologue (1:4-9) and the self-declarations at 8:12 and 9:5, now given as the culminating public statement of Jesus\' ministry.</p>',
    "47": '<p><strong>καὶ ἐάν τίς μου ἀκούσῃ τῶν ῥημάτων καὶ μὴ φυλάξῃ</strong> — "if anyone hears my words and does not keep them," aorist subjunctives (<em>akousē</em>, <em>phylaxē</em>). Both hearing and keeping are conditional; neither alone defines the relationship to Jesus\' words.</p><p><strong>οὐ κρίνω αὐτόν</strong> — "I do not judge him." The first-person negation is emphatic. The mission of the first coming is soteriological, not judicial — the contrast between 3:17 and the final judgment is repeated here.</p>',
    "48": '<p><strong>ὁ ἀθετῶν ἐμέ</strong> — "the one rejecting me," present participle of <em>atheteō</em> (G114, to set aside, refuse, reject — often of rejecting what has authority). The one who rejects is contrasted with the one who merely fails to keep (v.47); <em>atheteō</em> is active refusal rather than passive neglect.</p><p><strong>ὁ λόγος ὃν ἐλάλησα, ἐκεῖνος κρινεῖ αὐτὸν ἐν τῇ ἐσχάτῃ ἡμέρᾳ</strong> — "the word I have spoken, that word will judge him on the last day." The word (<em>logos</em>) is the instrument of judgment — not an external law imposed but the standard Jesus himself established in his ministry. The word stands as witness against those who rejected it.</p>',
    "49": '<p><strong>ὅτι ἐγὼ ἐξ ἐμαυτοῦ οὐκ ἐλάλησα</strong> — "because I have not spoken from myself," <em>ek emautou</em> (from myself/on my own authority). The divine origin of Jesus\' words is the ground for their judicial authority — they are not his private opinion but the Father\'s commission.</p><p><strong>ὁ πέμψας με πατήρ αὐτός μοι ἐντολὴν δέδωκεν</strong> — "the Father who sent me himself has given me commandment," perfect of <em>didōmi</em> — "has given and the commandment stands." <em>Entolē</em> (G1785, commandment) frames the Father\'s direction of Jesus\' speech as a standing directive.</p>',
    "50": '<p><strong>ἡ ἐντολὴ αὐτοῦ ζωὴ αἰώνιός ἐστιν</strong> — "his commandment is eternal life," <em>zōē aiōnios</em> (G2222 + G166). The equation is remarkable: the Father\'s instruction is not a path to eternal life but constitutes it. Obedience to the Father and eternal life are identified, not merely connected.</p><p><strong>καθὼς εἴρηκέν μοι ὁ πατήρ, οὕτως λαλῶ</strong> — "as the Father has spoken to me, so I speak," perfect of <em>legō</em>. The perfect <em>eirēken</em> marks the Father\'s word as the permanent source from which Jesus\' present speaking flows.</p>'
  },
  "13": {
    "1": '<p><strong>πρὸ δὲ τῆς ἑορτῆς τοῦ πάσχα</strong> — "before the festival of the Passover." The temporal marker sets this chapter earlier than the Synoptics\' Last Supper timeline; in John the crucifixion occurs on Nisan 14 (the day of Passover preparation) rather than Nisan 15, making Jesus the Passover lamb killed when the lambs are slaughtered.</p><p><strong>ἀγαπήσας τοὺς ἰδίους τοὺς ἐν τῷ κόσμῳ, εἰς τέλος ἠγάπησεν αὐτούς</strong> — "having loved his own who were in the world, he loved them to the end." <em>Agapaō</em> (G25) appears as a participle (prior love) then aorist (the definitive act). <em>Eis telos</em> (G5056) carries both temporal sense ("to the end, until the last moment") and qualitative sense ("completely, utterly") — the ambiguity is intentional; both are true of what follows in these chapters and at the cross.</p>',
    "2": '<p><strong>δείπνου γινομένου</strong> — "during supper being held/underway," present participle of <em>ginomai</em> — the meal is in progress, not concluded (contrast earlier translations that read "when supper was ended").</p><p><strong>τοῦ διαβόλου ἤδη βεβληκότος εἰς τὴν καρδίαν</strong> — "the devil having already cast into the heart," perfect active participle of <em>ballō</em> (G906, to throw/cast). The perfect marks the devil\'s prompting as a completed instigation: Judas\'s heart is already set before the meal\'s action begins. <em>Diabolos</em> (G1228, the accuser/slanderer) is used here rather than <em>Satanas</em> (13:27), noting both terms converge on the same figure.</p>',
    "3": '<p><strong>εἰδὼς ὅτι πάντα ἔδωκεν αὐτῷ ὁ πατήρ εἰς τὰς χεῖρας</strong> — "knowing that the Father had given all things into his hands," perfect of <em>didōmi</em>. The cosmic frame is essential: Jesus washes feet not in submission to the disciples but from a position of total authority. The humility is voluntary, not imposed.</p><p><strong>ἀπὸ θεοῦ ἐξῆλθεν καὶ πρὸς τὸν θεὸν ὑπάγει</strong> — "from God he came out and to God he is going," aorist of <em>exerchomai</em> + present of <em>hypagō</em>. The framing of Jesus\' existence between two divine termini — departure from God and return to God — is the theological ground for the shocking act that follows. He who spans eternity stoops to wash feet.</p>',
    "4": '<p><strong>τίθησιν τὰ ἱμάτια</strong> — "lays down his garments," present of <em>tithēmi</em> (G5087). The same verb is used for laying down one\'s life (10:11, 15, 17, 18; 13:37–38). The Evangelist chooses <em>tithēmi</em> for the garment-laying precisely to anticipate the cross-language.</p><p><strong>λέντιον διέζωσεν ἑαυτόν</strong> — "wrapped a linen cloth around himself," aorist of <em>diazōnnymi</em> (G1241). <em>Lention</em> (G3012) is a Latin loanword (<em>linteum</em>) — a linen towel, the garb of a household slave. The detail makes the status-inversion explicit.</p>',
    "5": '<p><strong>εἶτα βάλλει ὕδωρ εἰς τὸν νιπτῆρα</strong> — "then he pours water into the basin," present tense continuing the vivid narration. <em>Niptēr</em> (G3537, a washbasin) appears only here in NT.</p><p><strong>ἤρξατο νίπτειν τοὺς πόδας τῶν μαθητῶν</strong> — "he began to wash the feet of the disciples," <em>niptō</em> (G3538, to wash a body part). The distinction from <em>louō</em> (G3068, full bathing) matters for vv.9–10. Foot-washing was a task for the lowest-ranked household slave, not for a rabbi — this is the crux of Peter\'s objection.</p>',
    "6": '<p><strong>κύριε, σύ μου νίπτεις τοὺς πόδας</strong> — "Lord, are you washing my feet?" The word order in Greek puts <em>su</em> (you) immediately after the address, making the contrast emphatic: <em>You</em> — of all people — wash <em>my</em> feet? Peter\'s objection registers the role-reversal as an impropriety, not merely a surprise.</p>',
    "7": '<p><strong>ὃ ἐγὼ ποιῶ σὺ οὐκ οἶδας ἄρτι</strong> — "what I am doing you do not understand now," present of <em>oida</em> (G1492). <em>Arti</em> (G737, now/at this moment) — current incomprehension is normal; understanding will come. The word <em>oida</em> in John often denotes deeper comprehension, not surface knowledge; Peter\'s deficiency is theological, not informational.</p><p><strong>γνώσῃ δὲ μετὰ ταῦτα</strong> — "but you will know after these things," future of <em>ginōskō</em>. The post-resurrection understanding promised to the disciples (cf. 12:16) is anticipated here.</p>',
    "8": '<p><strong>οὐ μὴ νίψῃς μου τοὺς πόδας εἰς τὸν αἰῶνα</strong> — "you shall by no means wash my feet forever," strong negation (<em>ou mē</em> + aorist subjunctive). <em>Eis ton aiōna</em> ("into the age") is the standard emphatic expression for "never" in a permanent sense. Peter\'s refusal is categorical.</p><p><strong>οὐκ ἔχεις μέρος μετ᾽ ἐμοῦ</strong> — "you have no part with me," present of <em>echō</em>. <em>Meros</em> (G3313, part/share) carries the sense of participation and belonging — an inheritance or allotment term (cf. Josh 14:4 LXX; Rev 20:6). Exclusion from <em>meros</em> is exclusion from the shared life Jesus offers.</p>',
    "9": '<p><strong>μὴ μόνον τοὺς πόδας ἀλλὰ καὶ τὰς χεῖρας καὶ τὴν κεφαλήν</strong> — "not only my feet but also my hands and head." Peter\'s characteristic overcorrection swings from categorical refusal to total submission. The three body parts (feet, hands, head) may reflect a complete-cleansing idiom, or simply Petrine impulsiveness.</p>',
    "10": '<p><strong>ὁ λελουμένος οὐ χρείαν ἔχει εἰ μὴ τοὺς πόδας νίψασθαι</strong> — "the one who has bathed does not need anything except to wash his feet," perfect passive participle of <em>louō</em> (G3068, full immersion bathing). The distinction between <em>louō</em> (whole-body bath, once) and <em>niptō</em> (partial washing, ongoing) is deliberate. A person who has bathed needs only foot-cleaning after walking — the metaphor suggests that the disciples have already received comprehensive cleansing (discipleship with Jesus) and need only the ongoing foot-washing (continued service and humility).</p><p><strong>καὶ ὑμεῖς καθαροί ἐστε, ἀλλ᾽ οὐχὶ πάντες</strong> — "and you are clean, but not all of you," <em>katharos</em> (G2513, clean/pure). The qualification "not all" prepares for v.11\'s identification of Judas, and anticipates the moral dimension of the cleansing metaphor.</p>',
    "11": '<p><strong>ᾔδει γὰρ τὸν παραδιδόντα αὐτόν</strong> — "for he knew the one who was betraying him," pluperfect of <em>oida</em> — "had known." The parenthetical narrator comment reveals that Jesus\' "not all" in v.10 was deliberate and knowing, not uncertain.</p>',
    "12": '<p><strong>ἔλαβεν τὰ ἱμάτια αὐτοῦ καὶ ἀνέπεσεν πάλιν</strong> — "he took his garments and reclined again," aorists marking the resumption of normal table position. The deliberateness of putting garments back on — completing the re-dressing before asking the interpretive question — underlines that this is a structured teaching act, not spontaneous.</p><p><strong>γινώσκετε τί πεποίηκα ὑμῖν</strong> — "do you understand what I have done for you?" present of <em>ginōskō</em> + perfect of <em>poieō</em>. The completed act now awaits interpretation — the question is pedagogical, inviting reflection before explanation.</p>',
    "13": '<p><strong>ὁ διδάσκαλος καὶ ὁ κύριος</strong> — "the Teacher and the Lord," both with the definite article. These titles represent the two poles of Jesus\' acknowledged authority: <em>didaskalos</em> (G1320, rabbi/teacher) is the common address used by disciples; <em>kyrios</em> (G2962, Lord/master) acknowledges sovereign authority. Jesus affirms both simultaneously.</p><p><strong>καλῶς λέγετε, εἰμὶ γάρ</strong> — "you speak rightly, for I am," present of <em>eimi</em>. The affirmation is unqualified — Jesus does not diminish the titles but draws on their combined authority for the foot-washing argument.</p>',
    "14": '<p><strong>εἰ οὖν ἐγὼ ἔνιψα ὑμῶν τοὺς πόδας ὁ κύριος καὶ ὁ διδάσκαλος</strong> — "if then I, the Lord and the Teacher, washed your feet," aorist of <em>niptō</em>. The conditional is real (first class implied): he did wash them. The argument from the greater to the lesser (<em>a fortiori</em>) is explicit — if the one of higher rank performed the act, those of lower rank are obligated.</p><p><strong>ὀφείλετε καὶ ὑμεῖς ἀλλήλων νίπτειν τοὺς πόδας</strong> — "you also ought to wash one another\'s feet," present infinitive of <em>niptō</em> indicating an ongoing obligation. <em>Opheilō</em> (G3784, to owe/ought) is not mere suggestion but moral obligation derived from the enacted example.</p>',
    "15": '<p><strong>ὑπόδειγμα γὰρ δέδωκα ὑμῖν</strong> — "for I have given you an example," perfect of <em>didōmi</em>. <em>Hypodeigma</em> (G5261, example/pattern/model) appears here for the first time in John — this is the interpretive key Jesus provides. Not a one-time rite but a repeatable pattern of servant-action among equals.</p><p><strong>ἵνα καθὼς ἐγὼ ἐποίησα ὑμῖν, καὶ ὑμεῖς ποιῆτε</strong> — "so that as I did for you, you also might do," aorist subjunctive of <em>poieō</em>. The <em>kathōs</em> (just as) establishes correspondence of kind, not merely of external form — the quality of self-giving is the model, not the literal act only.</p>',
    "16": '<p><strong>οὐκ ἔστιν δοῦλος μείζων τοῦ κυρίου αὐτοῦ</strong> — "a servant is not greater than his master," present of <em>eimi</em>. The principle appears also at 15:20; the axiom is well-attested in Jewish wisdom literature. Applied here: if the master washed feet, the servant has no grounds to refuse to do the same.</p><p><strong>οὐδὲ ἀπόστολος μείζων τοῦ πέμψαντος αὐτόν</strong> — "nor is a messenger/apostle greater than the one who sent him." <em>Apostolos</em> (G652) appears only here in John — the only occurrence in the entire Gospel. The word means "sent one" (from <em>apostellō</em>, G649) — the parallel with <em>pempō</em> (sent) is intentional: Jesus is himself the one sent by the Father (passim), and the disciples are sent by him.</p>',
    "17": '<p><strong>εἰ ταῦτα οἴδατε, μακάριοί ἐστε ἐὰν ποιῆτε αὐτά</strong> — "if you know these things, you are blessed if you do them." Two conditionals bracket the promise: knowing (<em>oida</em>) and doing (<em>poieō</em>). <em>Makarios</em> (G3107, blessed/happy) is a beatitude-form — the only such form in John\'s Gospel. Knowing without doing produces no blessing; action in conformity with knowledge does.</p>',
    "18": '<p><strong>οὐ περὶ πάντων ὑμῶν λέγω</strong> — "I am not speaking about all of you," present of <em>legō</em>. The assurance of v.17 is explicitly not addressed to Judas — the exception is stated before the citation so readers understand Jesus\' blessing has not missed the betrayal.</p><p><strong>ὁ τρώγων μου τὸν ἄρτον ἐπῆρεν ἐπ᾽ ἐμὲ τὴν πτέρναν αὐτοῦ</strong> — Ps 41:9 (LXX 40:10) citation. <em>Trōgō</em> (G5176, to gnaw or crunch) is a more visceral eating verb than <em>esthiō</em> (G2068) — the LXX uses <em>esthiō</em> but John\'s version upgrades to <em>trōgō</em>, the same verb Jesus used for eating his flesh at 6:54–58. The betrayal occurs in the context of shared bread, which was the ultimate expression of covenant solidarity in the ancient world.</p>',
    "19": '<p><strong>ἵνα πιστεύσητε ὅτι ἐγώ εἰμι</strong> — "so that you may believe that I am," aorist subjunctive of <em>pisteuō</em>. <strong>ἐγώ εἰμι</strong> without predicate is the Johannine absolute divine self-identification (cf. 8:24, 28, 58), carrying the register of the divine name from Exod 3:14 (LXX: ἐγώ εἰμι ὁ ὤν) and Isa 43:10 (LXX: ἐγώ εἰμι). Foreknowledge of the betrayal, announced before it happens, becomes evidence for the disciples that Jesus operates from divine knowledge.</p>',
    "20": '<p><strong>ὁ λαμβάνων ἄν τινα πέμψω ἐμὲ λαμβάνει</strong> — "whoever receives anyone I send receives me," present participle of <em>lambanō</em>. The chain of reception (agent → sender → Father) mirrors the chain of revelation in John\'s theology: receiving the apostle is receiving Jesus; receiving Jesus is receiving the Father. The commissioning authority flows unbroken from the Father through Jesus to the sent ones.</p>',
    "21": '<p><strong>ἐταράχθη τῷ πνεύματι</strong> — "was troubled in spirit," aorist passive of <em>tarassō</em> (G5015) + dative <em>pneumati</em>. This is the same disturbance as at 11:33 (the tomb) and echoes 12:27 (the hour of death). The localization "in spirit" (<em>pneumati</em>) distinguishes this from the purely emotional; it is disturbance at the deepest level of Jesus\' being.</p><p><strong>ἀμὴν ἀμὴν λέγω ὑμῖν ὅτι εἷς ἐξ ὑμῶν παραδώσει με</strong> — "truly truly I tell you, one of you will betray me," future of <em>paradidōmi</em>. The doubled-amen formula marks solemn revelation; the betrayal, already anticipated from 6:71 and 12:4, is now formally announced at table.</p>',
    "22": '<p><strong>ἔβλεπον εἰς ἀλλήλους οἱ μαθηταί</strong> — "the disciples were looking at one another," imperfect of <em>blepō</em> — mutual, repeated glancing. The imperfect captures the prolonged confused exchange as each searches the others\' faces.</p><p><strong>ἀπορούμενοι περὶ τίνος λέγει</strong> — "at a loss about whom he was speaking," present participle of <em>aporeō</em> (G639, to be at a loss, have no way out). The disciples\' uncertainty is genuine — Judas\'s hidden intention has not been visible to them.</p>',
    "23": '<p><strong>εἷς ἐκ τῶν μαθητῶν αὐτοῦ ἐν τῷ κόλπῳ τοῦ Ἰησοῦ</strong> — "one of his disciples in the bosom of Jesus," <em>kolpos</em> (G2859, bosom/chest/lap) — the position of intimate reclining at a banquet, next to the host. The same word is used for Jesus\' relationship with the Father at 1:18 ("the one in the bosom of the Father"). The beloved disciple\'s position mirrors Jesus\' own position with the Father.</p><p><strong>ὃν ἠγάπα ὁ Ἰησοῦς</strong> — "whom Jesus loved," imperfect of <em>agapaō</em>. The imperfect marks sustained, ongoing love, not a single act. This is the first explicit designation of "the disciple whom Jesus loved" — the anonymous witness whose testimony underlies the Gospel (21:24).</p>',
    "24": '<p><strong>νεύει οὖν τούτῳ Σίμων Πέτρος</strong> — "Simon Peter therefore nods to this one," present of <em>neuō</em> (G3506, to nod or beckon). A silent gesture across the reclining group — Peter cannot ask directly without disrupting the meal, so he signals the beloved disciple who has better access to Jesus.</p>',
    "25": '<p><strong>ἐπιπεσὼν δὲ ἐκεῖνος οὕτως ἐπὶ τὸ στῆθος τοῦ Ἰησοῦ</strong> — "leaning back in that way upon the breast of Jesus," aorist participle of <em>epipiptō</em> (G1968, to fall upon/lean against). The reclining posture makes the question physically intimate; the beloved disciple simply leans back to whisper.</p>',
    "26": '<p><strong>ἐκεῖνός ἐστιν ᾧ ἐγὼ βάψω τὸ ψωμίον</strong> — "that one is the one to whom I will dip the piece of bread," future of <em>baptō</em> (G911, to dip). <em>Psōmion</em> (G5596, a morsel or small piece) is a piece of bread dipped in sauce or the dish. Offering a dipped morsel was an act of honor at a Middle Eastern meal — the host singles out a guest for distinction.</p><p><strong>δοὺς τῷ Ἰούδᾳ Σίμωνος Ἰσκαριώτου</strong> — "having given it to Judas son of Simon Iscariot," aorist participle. The identification by name and patronymic at the moment of the morsel is the Evangelist\'s literary climax of the scene.</p>',
    "27": '<p><strong>εἰσῆλθεν εἰς ἐκεῖνον ὁ σατανᾶς</strong> — "Satan entered into that one," aorist of <em>eiserchomai</em>. <em>Satanas</em> (G4567) here compared to <em>diabolos</em> in v.2 — both terms are used for the adversary; the shift may indicate an escalation from prompting (v.2) to full possession/control. The entrance is the counterpart to the morsel: an act of honor becomes the vehicle of darkness.</p><p><strong>ὃ ποιεῖς ποίησον τάχιον</strong> — "what you are doing, do more quickly," present + aorist imperative of <em>poieō</em>. <em>Tachion</em> (G5032, comparative of <em>tachy</em>, quickly) — Jesus is not hastening the betrayal for pragmatic reasons but releasing Judas to his chosen course. The authority of the command underlines that even this falls within Jesus\' sovereignty.</p>',
    "28": '<p><strong>τοῦτο δὲ οὐδεὶς ἔγνω τῶν ἀνακειμένων πρὸς τί εἶπεν αὐτῷ</strong> — "but no one of those reclining knew for what reason he said this to him," aorist of <em>ginōskō</em>. The narrator\'s aside emphasizes the opacity — the exchange between Jesus and Judas was perceived only by the beloved disciple (v.26) and perhaps Peter; the rest remain uninformed.</p>',
    "29": '<p><strong>τινὲς γὰρ ἐδόκουν ἐπεὶ τὸ γλωσσόκομον εἶχεν Ἰούδας</strong> — "for some thought, since Judas had the money bag," imperfect of <em>dokeō</em> (G1380, to think/suppose). The narrator records the plausible misreading — Judas\' role as treasurer made the most natural interpretation one of errand-running, not betrayal. The irony is that the disciples\' charity toward Judas was misplaced.</p>',
    "30": '<p><strong>εὐθέως οὖν ἐξῆλθεν</strong> — "immediately therefore he went out," aorist of <em>exerchomai</em>. The adverb <em>eutheōs</em> (G2112, immediately) marks the speed of response — the decision is irrevocable, the course set.</p><p><strong>ἦν δὲ νύξ</strong> — "and it was night," <em>nyx</em> (G3571). Two words in Greek, but among the most theologically dense in the Gospel. <em>Nyx</em> is not only a temporal marker but the Johannine symbol for spiritual darkness, opposition to the light (1:5; 3:19; 11:10). Judas goes out into the night in every sense.</p>',
    "31": '<p><strong>νῦν ἐδοξάσθη ὁ Υἱὸς τοῦ ἀνθρώπου</strong> — "now the Son of Man was glorified," aorist passive of <em>doxazō</em>. The aorist is proleptic — the glorification has not yet occurred, but with Judas\' departure the cross is now inevitable and imminent; the aorist treats the outcome as already secured. <em>Nun</em> (now) ties the glorification to this very moment of the betrayal\'s activation.</p>',
    "32": '<p><strong>εἰ ὁ θεὸς ἐδοξάσθη ἐν αὐτῷ, καὶ ὁ θεὸς δοξάσει αὐτὸν ἐν αὐτῷ</strong> — "if God was glorified in him, God will also glorify him in himself." The conditional is not uncertain but logical: because the Father has been glorified in the Son\'s mission, the Father will reciprocally glorify the Son. The mutual glorification is the structure of John\'s theology of the cross.</p><p><strong>καὶ εὐθὺς δοξάσει αὐτόν</strong> — "and will glorify him at once," <em>eutheōs</em> (G2112). The immediacy of the coming glorification matches the immediacy of Judas\' exit — the timetable is now compressed.</p>',
    "33": '<p><strong>τεκνία</strong> — "little children," diminutive of <em>teknon</em> (G5040). This is the only occurrence of <em>teknia</em> in John\'s Gospel (though common in 1 John). The term of endearment marks the shift in tone from instruction to farewell.</p><p><strong>ζητήσετέ με, καὶ καθὼς εἶπον τοῖς Ἰουδαίοις ὅτι ὅπου ὑπάγω ἐγὼ ὑμεῖς οὐ δύνασθε ἐλθεῖν</strong> — "you will seek me, and as I told the Jews that where I am going you cannot come." The language of departure echoes 7:33–34 and 8:21, but with different pathos — what was said as warning to opponents is now said as sorrowful farewell to the beloved disciples.</p>',
    "34": '<p><strong>ἐντολὴν καινὴν δίδωμι ὑμῖν</strong> — "a new commandment I give you," present of <em>didōmi</em>. <em>Kainos</em> (G2537, new in kind/quality, as opposed to <em>neos</em>, new in time) signals that the commandment is not merely added to existing law but is of a different order. The love commandment is not unprecedented (Lev 19:18) — what makes it "new" is the standard given in v.34b.</p><p><strong>ἀγαπᾶτε ἀλλήλους, καθὼς ἠγάπησα ὑμᾶς</strong> — "love one another, as I have loved you," present imperative + aorist of <em>agapaō</em>. The <em>kathōs</em> (just as) makes Christ\'s own love the measure and model — not the natural impulse to love those who love you, but a love shaped by the self-giving pattern of 13:1–17 and the cross. The aorist <em>ēgapēsa</em> encapsulates the completed act now being described as the standard.</p>',
    "35": '<p><strong>ἐν τούτῳ γνώσονται πάντες ὅτι ἐμοὶ μαθηταί ἐστε</strong> — "by this all will know that you are my disciples," future of <em>ginōskō</em>. The criterion of recognizable discipleship is not adherence to teaching, observance of ritual, or organizational affiliation — it is mutual love.</p><p><strong>ἐὰν ἀγάπην ἔχητε ἐν ἀλλήλοις</strong> — "if you have love among one another," <em>agapē</em> (G26, disp=3). The disputed semantic range of <em>agapē</em> — from "warm affection" to "selfless covenantal love" — is resolved by context: the standard in v.34 (<em>kathōs ēgapēsa hymas</em>) demands a love shaped by Christ\'s own self-giving, which is not adequately described as mere affection. The observable social reality of this love becomes the community\'s public witness.</p>',
    "36": '<p><strong>κύριε, ποῦ ὑπάγεις</strong> — "Lord, where are you going?" Peter\'s question interrupts the farewell; <em>hypagō</em> (G5217, to go/depart) is the departure verb John uses for Jesus\' movement toward death and to the Father (cf. 7:33; 8:14, 21–22; 13:33).</p><p><strong>οὐ δύνασαί μοι νῦν ἀκολουθῆσαι, ἀκολουθήσεις δὲ ὕστερον</strong> — "you are not able to follow me now, but you will follow later," present of <em>dynamai</em> + future of <em>akoloutheō</em>. The <em>hysteron</em> (later) gestures toward Peter\'s martyrdom (21:18–19), where he will indeed follow Jesus in the way of the cross.</p>',
    "37": '<p><strong>κύριε, διὰ τί οὐ δύναμαί σοι ἀκολουθεῖν ἄρτι</strong> — "Lord, why am I not able to follow you now?" Peter\'s <em>arti</em> (now) echoes Jesus\' <em>arti</em> in v.7 (you do not understand now) — Peter still does not grasp the nature of what following Jesus will require.</p><p><strong>τὴν ψυχήν μου ὑπὲρ σοῦ θήσω</strong> — "I will lay down my life for you," future of <em>tithēmi</em>, the same verb used for Jesus\' own life-laying in 10:11, 15. Peter claims to be ready for what is in fact Jesus\' unique role — the confidence is sincere but premature.</p>',
    "38": '<p><strong>τὴν ψυχήν σου ὑπὲρ ἐμοῦ θήσεις</strong> — "you will lay down your life for me?" The echo of Peter\'s own words (v.37) turned into a question — Jesus neither affirms the claim nor rejects it as impossible (Peter will eventually die for Christ), but punctures the immediate confidence.</p><p><strong>ἀμὴν ἀμὴν λέγω σοι, οὐ μὴ ἀλέκτωρ φωνήσῃ ἕως οὗ ἀρνήσῃ με τρίς</strong> — "truly truly I tell you, the rooster will not crow until you have denied me three times," double aorist subjunctives with the strong negation <em>ou mē</em>. <em>Alektōr</em> (G220, rooster) appears only in denial-prophecy passages in all four Gospels. The tripling of the denial (<em>tris</em>) will be fulfilled in 18:15–27 with precision.</p>'
  }
}


